namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string Room { get; set; } = "";
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their significance." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 research papers and holds two patents in natural language processing.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor of Computer Science", Bio = "Dr. Martinez focuses on distributed systems and cloud computing. He previously worked as a senior engineer at a major tech company for 10 years.", Email = "rmartinez@university.edu" },
            new() { Id = 3, Name = "Dr. Sarah Kim", Title = "Professor of Mathematics", Bio = "Dr. Kim is an expert in abstract algebra and number theory. She has received multiple awards for excellence in undergraduate teaching.", Email = "skim@university.edu" },
            new() { Id = 4, Name = "Dr. James Wilson", Title = "Associate Professor of Mathematics", Bio = "Dr. Wilson specializes in applied mathematics and statistical modeling. His research focuses on computational methods for real-world problems.", Email = "jwilson@university.edu" },
            new() { Id = 5, Name = "Prof. Emily Brooks", Title = "Professor of English", Bio = "Prof. Brooks is a published novelist and literary critic specializing in contemporary American fiction and creative writing pedagogy.", Email = "ebrooks@university.edu" },
            new() { Id = 6, Name = "Dr. Michael Torres", Title = "Professor of Physics", Bio = "Dr. Torres conducts research in quantum mechanics and particle physics. He has collaborated with CERN on multiple experiments.", Email = "mtorres@university.edu" },
            new() { Id = 7, Name = "Dr. Linda Park", Title = "Associate Professor of History", Bio = "Dr. Park specializes in East Asian history and transnational studies. She has authored three books on modern Korean history.", Email = "lpark@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Room = "Science Hall 201", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM", Room = "Science Hall 305", DepartmentId = 1, Instructor = _instructors[1], Department = _departments[0], IsFeatured = true },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Covers relational database design, SQL, normalization, indexing, and transaction management. Includes a semester-long project building a complete database application.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Room = "Science Hall 110", DepartmentId = 1, Instructor = _instructors[1], Department = _departments[0] },
            new() { Id = 4, Code = "CS 420", Title = "Artificial Intelligence", Description = "Introduction to AI concepts including search algorithms, knowledge representation, machine learning fundamentals, and neural networks.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Room = "Science Hall 405", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = true },
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Room = "Math Building 101", DepartmentId = 2, Instructor = _instructors[2], Department = _departments[1], IsFeatured = true },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to systems of equations.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Room = "Math Building 203", DepartmentId = 2, Instructor = _instructors[3], Department = _departments[1] },
            new() { Id = 7, Code = "MATH 301", Title = "Abstract Algebra", Description = "Groups, rings, and fields. Explores the algebraic structures underlying modern mathematics and cryptography.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Room = "Math Building 305", DepartmentId = 2, Instructor = _instructors[2], Department = _departments[1] },
            new() { Id = 8, Code = "ENG 101", Title = "College Composition", Description = "Develop critical reading and writing skills through analysis of diverse texts. Emphasis on argumentation, research methods, and clear prose.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Room = "Humanities 120", DepartmentId = 3, Instructor = _instructors[4], Department = _departments[2] },
            new() { Id = 9, Code = "ENG 250", Title = "American Literature", Description = "Survey of major works in American literature from the colonial period to the present. Explores themes of identity, freedom, and the American experience.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", Room = "Humanities 215", DepartmentId = 3, Instructor = _instructors[4], Department = _departments[2] },
            new() { Id = 10, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to physics with weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Thu Lab 2:00–4:50 PM", Room = "Physics Lab 100", DepartmentId = 4, Instructor = _instructors[5], Department = _departments[3], IsFeatured = true },
            new() { Id = 11, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory. Prerequisites: PHYS 101, MATH 201.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", Room = "Physics Lab 310", DepartmentId = 4, Instructor = _instructors[5], Department = _departments[3] },
            new() { Id = 12, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory through the Renaissance. Explores political, cultural, and economic developments across regions.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", Room = "Liberal Arts 200", DepartmentId = 5, Instructor = _instructors[6], Department = _departments[4] },
            new() { Id = 13, Code = "HIST 220", Title = "Modern East Asia", Description = "History of China, Japan, and Korea from the 19th century to the present. Focuses on modernization, conflict, and cultural change.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", Room = "Liberal Arts 310", DepartmentId = 5, Instructor = _instructors[6], Department = _departments[4] },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

