@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4">University Course Catalog</h1>
    <p class="lead text-muted">Explore departments, discover courses, and enroll for the upcoming semester.</p>
    <a href="courses" class="btn btn-primary btn-lg mt-2">Browse All Courses</a>
</div>

<h2 class="mb-3">Featured Courses</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mb-5">
    @foreach (var course in featuredCourses)
    {
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">@course.Code — @course.Title</h5>
                    <p class="card-text text-muted">@course.Department.Name · @course.Credits credits</p>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mb-3">Departments</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mb-4">
    @foreach (var dept in departments)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<UniversityCourseCatalog.Models.Course> featuredCourses = new();
    private List<UniversityCourseCatalog.Models.Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

