@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses, instructors…"
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (filteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.Department.Name</td>
                        <td>@course.Credits</td>
                        <td>@course.Instructor.Name</td>
                        <td>@course.Schedule</td>
                        <td>
                            <a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private string searchTerm = "";
    private int selectedDepartmentId;
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        UpdateResults();
    }

    private void UpdateResults()
    {
        filteredCourses = Catalog.SearchCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }

    private string SearchTerm
    {
        get => searchTerm;
        set { searchTerm = value; UpdateResults(); }
    }

    // Re-filter whenever any bound property changes
    protected override void OnParametersSet() => UpdateResults();
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@selectedCourseDisplay</strong> has been received.</p>
        <hr />
        <p class="mb-0">You will receive a confirmation email at your university account. <a href="courses">Browse more courses</a>.</p>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-6">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" required
                           @bind="Model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" required
                           placeholder="e.g. S12345678"
                           @bind="Model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" required @bind="Model.CourseId">
                        <option value="0" disabled selected>Select a course…</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </select>
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    private int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseDisplay = "";

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(Model.CourseId);
        selectedCourseDisplay = course is not null ? $"{course.Code} — {course.Title}" : "Unknown Course";
        Catalog.SubmitEnrollment(Model);
        submitted = true;
    }
}

